import requests
from datetime import datetime, timedelta, timezone

GRAFANA_URL = "https://grafana.internal"
GRAFANA_TOKEN = "glsa_..."  # service account token, read-only
HEADERS = {"Authorization": f"Bearer {GRAFANA_TOKEN}"}


def list_all_dashboards():
    resp = requests.get(f"{GRAFANA_URL}/api/search?type=dash-db&limit=500", headers=HEADERS)
    resp.raise_for_status()
    return resp.json()


def get_dashboard(uid: str):
    resp = requests.get(f"{GRAFANA_URL}/api/dashboards/uid/{uid}", headers=HEADERS)
    resp.raise_for_status()
    return resp.json()["dashboard"]


def check_owner_tags(dashboard: dict) -> list[str]:
    """Return missing required tag prefixes."""
    tags = dashboard.get("tags", [])
    required_prefixes = ["owner:", "team:", "last-reviewed:"]
    return [p for p in required_prefixes if not any(t.startswith(p) for t in tags)]


def check_last_reviewed(dashboard: dict, max_age_days: int = 90) -> bool:
    """Return True if the dashboard is overdue for review."""
    tags = dashboard.get("tags", [])
    for tag in tags:
        if tag.startswith("last-reviewed:"):
            date_str = tag.split(":", 1)[1]  # e.g. "2025-10-01"
            reviewed = datetime.strptime(date_str, "%Y-%m-%d").replace(tzinfo=timezone.utc)
            return (datetime.now(timezone.utc) - reviewed).days > max_age_days
    return True  # No last-reviewed tag means overdue


def audit():
    dashboards = list_all_dashboards()
    stale = []
    for d in dashboards:
        dash = get_dashboard(d["uid"])
        missing_tags = check_owner_tags(dash)
        overdue = check_last_reviewed(dash)
        if missing_tags or overdue:
            stale.append({
                "title": dash["title"],
                "uid": d["uid"],
                "url": f"{GRAFANA_URL}/d/{d['uid']}",
                "missing_tags": missing_tags,
                "overdue_review": overdue,
            })
    return stale


if __name__ == "__main__":
    findings = audit()
    for f in findings:
        print(f"STALE: {f['title']} ({f['url']})")
        if f["missing_tags"]:
            print(f"  Missing tags: {f['missing_tags']}")
        if f["overdue_review"]:
            print("  Review overdue (> 90 days)")
